CREATE TABLE search_grid (
  id SERIAL PRIMARY KEY,
  geom GEOMETRY(Polygon, 4326),
  status TEXT, -- 'pending', 'in_progress', 'searched'
  last_searched TIMESTAMP
);

class SARPlanner(Node):
    def __init__(self):
        super().__init__('sar_planner')
        self.pattern_generator = GridSearch(altitude=50, spacing=30)
        self.waypoint_pub = self.create_publisher(Pose, '/waypoint', 10)

    def start_mission(self, area):
        waypoints = self.pattern_generator.generate(area)
        for wp in waypoints:
            self.waypoint_pub.publish(wp)
